parameters:
{
  "sources": {
    "earthquakes": {
      "db": "stg",
      "table": "USGS_Earthquakes",
      "business_keys": [
        "event_id"
      ],
      "filter": {
        "where_clause": "CAST(stg_load_date AS DATE) > '{{LastRunDateTime}}' AND event_id IS NOT NULL"
      }
    }
  },
  "target": {
    "db": "int",
    "table": "Earthquake_Event",
    "business_keys": [
      "Event_ID"
    ],
    "write_mode": "truncate_insert"
  },
  "transformation": {
    "steps": [
      {
        "step_id": 10,
        "name": "read_earthquakes",
        "type": "read_source",
        "config": {
          "source_name": "earthquakes",
          "alias": "df_earthquakes"
        }
      },
      {
        "step_id": 20,
        "name": "deduplicate_events",
        "type": "deduplicate",
        "config": {
          "input_df": "df_earthquakes",
          "alias": "df_dedup",
          "partition_by": [
            "event_id"
          ],
          "order_by": [
            {
              "column": "updated_epoch_ms",
              "direction": "desc"
            }
          ]
        }
      },
      {
        "step_id": 30,
        "name": "select_event_columns",
        "type": "select",
        "config": {
          "input_df": "df_dedup",
          "alias": "df_selected",
          "columns": [
            {
              "expr": "event_id",
              "alias": "Event_ID"
            },
            {
              "expr": "place",
              "alias": "Place"
            },
            {
              "expr": "magnitude",
              "alias": "Magnitude"
            },
            {
              "expr": "event_type",
              "alias": "Event_Type"
            },
            {
              "expr": "status",
              "alias": "Status"
            },
            {
              "expr": "tsunami_flag",
              "alias": "Tsunami_Flag"
            },
            {
              "expr": "significance",
              "alias": "Significance"
            },
            {
              "expr": "event_time_epoch_ms",
              "alias": "Event_Time_Epoch_Ms"
            },
            {
              "expr": "updated_epoch_ms",
              "alias": "Updated_Epoch_Ms"
            },
            {
              "expr": "longitude",
              "alias": "Longitude"
            },
            {
              "expr": "latitude",
              "alias": "Latitude"
            },
            {
              "expr": "depth_km",
              "alias": "Depth_Km"
            },
            {
              "expr": "event_url",
              "alias": "Event_URL"
            },
            {
              "expr": "stg_load_date",
              "alias": "stg_load_date"
            },
            {
              "expr": "batch_id",
              "alias": "batch_id"
            }
          ]
        }
      },
      {
        "step_id": 40,
        "name": "add_system_fields",
        "type": "add_system_fields",
        "config": {
          "input_df": "df_selected",
          "alias": "df_with_sys"
        }
      },
      {
        "step_id": 50,
        "name": "compute_hash",
        "type": "compute_hash",
        "config": {
          "input_df": "df_with_sys",
          "alias": "df_hashed"
        }
      },
      {
        "step_id": 60,
        "name": "write_target",
        "type": "write_target",
        "config": {
          "input_df": "df_hashed"
        }
      }
    ]
  }
}
